// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL
#define MAXM 10100LL
typedef struct { long long pos; int delta; } Event;
int cmpEvent(const void *a, const void *b) {
    long long pa = ((Event*)a)->pos;
    long long pb = ((Event*)b)->pos;
    if (pa < pb) return -1;
    if (pa > pb) return 1;
    return ((Event*)a)->delta - ((Event*)b)->delta;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        Event *ev = (Event*)malloc(sizeof(Event)*(2LL*N+5));
        int evCnt = 0;
        for(int i=0;i<N;i++){
            long long X, D; scanf("%lld %lld", &X, &D);
            long long L = D * X;
            long long R = (D + 1) * X - 1;
            if (L > MAXM || R < 0) continue; // no overlap
            if (L < 0) L = 0;
            if (R > MAXM) R = MAXM;
            ev[evCnt++] = (Event){L, 1};
            if (R + 1 <= MAXM) ev[evCnt++] = (Event){R + 1, -1};
        }
        qsort(ev, evCnt, sizeof(Event), cmpEvent);
        long long need = (long long)N - K;
        long long cur = 0, prev = 0, ans = 0;
        int idx = 0;
        while(idx < evCnt){
            long long pos = ev[idx].pos;
            if (prev < pos){
                long long len = (pos <= MAXM+1 ? pos : MAXM+1) - prev;
                if (cur >= need) ans = (ans + len) % MOD;
                prev = pos;
            }
            while(idx < evCnt && ev[idx].pos == pos){
                cur += ev[idx].delta;
                idx++;
            }
        }
        if (prev <= MAXM){
            long long len = (MAXM + 1) - prev;
            if (cur >= need) ans = (ans + len) % MOD;
        }
        printf("%lld\n", ans % MOD);
        free(ev);
    }
    return 0;
}

