// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;
const long long MAXM = 10100LL;
struct Event{ long long pos; int delta; };
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N, K; cin>>N>>K;
        vector<Event> ev; ev.reserve(2LL*N+5);
        for(int i=0;i<N;i++){
            long long X,D; cin>>X>>D;
            long long L = D*X;
            long long R = (D+1)*X - 1;
            if(L>MAXM || R<0) continue;
            L = max(L, 0LL);
            R = min(R, MAXM);
            ev.push_back({L,1});
            if(R+1<=MAXM) ev.push_back({R+1,-1});
        }
        sort(ev.begin(), ev.end(), [](const Event&a,const Event&b){return a.pos<b.pos;});
        long long need = (long long)N - K;
        long long cur=0, prev=0, ans=0;
        size_t idx=0;
        while(idx<ev.size()){
            long long pos = ev[idx].pos;
            if(prev<pos){
                long long len = min(pos, MAXM+1) - prev;
                if(cur>=need) ans = (ans + len)%MOD;
                prev = pos;
            }
            while(idx<ev.size() && ev[idx].pos==pos){
                cur += ev[idx].delta;
                ++idx;
            }
        }
        if(prev<=MAXM){
            long long len = (MAXM+1) - prev;
            if(cur>=need) ans = (ans + len)%MOD;
        }
        cout<<ans%MOD<<"\n";
    }
    return 0;
}
